user_prompt_template:
System Architecture:
{upstream_json}

Design a worksheet system for this operational system. Return ONLY valid JSON — no markdown, no prose.

Required schema:
{{
  "worksheet_system_name": "string",
  "worksheets": [
    {{
      "id": "string — slug like 'ws-01'",
      "title": "string",
      "domain": "string — must match a control domain from the architecture",
      "purpose": "string — one sentence",
      "sections": [
        {{
          "section_title": "string",
          "fields": [
            {{
              "field_id": "string",
              "label": "string",
              "type": "text|date|boolean|number|select|multi-select",
              "options": ["string"],
              "required": true
            }}
          ]
        }}
      ],
      "decision_gates": [
        {{
          "gate_id": "string",
          "condition": "string — decision condition",
          "pass_action": "string",
          "fail_action": "string"
        }}
      ]
    }}
  ],
  "completion_sequence": ["string — ordered worksheet IDs"]
}}
